(function($){$.fn.passwordStrengthMeter=function(options){var settings=$.extend({},$.fn.passwordStrengthMeter.defaults,options);return this.each(function(){var $this=$(this);var $passwordField=$this.find('input[type="password"]');var $strengthMeter=$this.find('.password-strength-meter');var $strengthText=$this.find('.password-strength-text');if($passwordField.length===0||$strengthMeter.length===0){return}$passwordField.on('input',function(){var password=$(this).val();if(password.length===0){$strengthMeter.removeClass().addClass('password-strength-meter');$strengthText.text('');return}var result=zxcvbn(password);var strengthClass='strength-'+result.score;var strengthText=settings.strengthTexts[result.score]||'';$strengthMeter.removeClass().addClass('password-strength-meter '+strengthClass);$strengthText.text(strengthText);if(settings.onStrengthChange){settings.onStrengthChange(result.score,result.feedback)}})});};$.fn.passwordStrengthMeter.defaults={strengthTexts:['Very Weak','Weak','Fair','Good','Strong'],onStrengthChange:null};})(jQuery);
